import{_ as t,o as a,c as e,ag as l}from"./chunks/framework.wqPkq5Rj.js";const n=JSON.parse('{"title":"和 momo 说话，需要一点技巧","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/talking-to-momo.md","filePath":"advanced/talking-to-momo.md","lastUpdated":1777169627000}'),u={name:"advanced/talking-to-momo.md"};function c(i,o,r,s,q,p){return a(),e("div",null,[...o[0]||(o[0]=[l('<h1 id="和-momo-说话-需要一点技巧" tabindex="-1">和 momo 说话，需要一点技巧 <a class="header-anchor" href="#和-momo-说话-需要一点技巧" aria-label="Permalink to &quot;和 momo 说话，需要一点技巧&quot;">​</a></h1><p>我不会读心术。你说得越清楚，我做得越好。不需要学&quot;提示词工程&quot;——只需要养成几个说话习惯。</p><hr><h2 id="把需求说清楚" tabindex="-1">把需求说清楚 <a class="header-anchor" href="#把需求说清楚" aria-label="Permalink to &quot;把需求说清楚&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">不够好</p><p>&quot;帮我写一下这个功能的介绍。&quot;</p></div><div class="tip custom-block"><p class="custom-block-title">更好的方式</p><p>&quot;帮我写一段 200 字以内的功能介绍，放在官网首页，读者是不熟悉 AI 工具的中小企业主，要让他们一眼看懂我们能帮他们省什么时间。给我三个方向选。&quot;</p></div><p>一句话里把<strong>给谁看、用在哪、什么目的、什么格式</strong>说清楚，我给你的结果会完全不同。</p><hr><h2 id="允许我问你问题" tabindex="-1">允许我问你问题 <a class="header-anchor" href="#允许我问你问题" aria-label="Permalink to &quot;允许我问你问题&quot;">​</a></h2><p>遇到复杂任务，可以这样说：</p><blockquote><p>&quot;在你开始之前，如果有需要确认的信息，先问我。&quot;</p></blockquote><p>这样我不会靠猜测补全你没提供的信息，而是把问题暴露出来。我们确认完再开工，省去来回修改的成本。</p><hr><h2 id="把大任务拆开" tabindex="-1">把大任务拆开 <a class="header-anchor" href="#把大任务拆开" aria-label="Permalink to &quot;把大任务拆开&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">不够好</p><p>&quot;帮我做一份完整的竞品分析报告。&quot;</p></div><div class="tip custom-block"><p class="custom-block-title">更好的方式</p><ul><li>第一步：&quot;帮我列出我们最主要的 5 个竞品。&quot;</li><li>第二步：&quot;针对这个竞品，帮我分析它的定价策略。&quot;</li><li>第三步：&quot;现在把刚才所有竞品的定价汇总成一张对比表。&quot;</li></ul></div><p>一次发一个清晰的指令，比一次发一个模糊的大任务，效率高很多。</p><hr><h2 id="不满意就直接说" tabindex="-1">不满意就直接说 <a class="header-anchor" href="#不满意就直接说" aria-label="Permalink to &quot;不满意就直接说&quot;">​</a></h2><blockquote><p>&quot;这段语气太正式了，改得口语一点。&quot;</p></blockquote><blockquote><p>&quot;结论太模糊，我需要一个明确的建议，你推荐哪个方案？&quot;</p></blockquote><blockquote><p>&quot;太长了，压缩到 100 字以内。&quot;</p></blockquote><p>我不会因为你提意见而&quot;生气&quot;。反馈越具体，调整越快。</p><hr><h2 id="最后一件事" tabindex="-1">最后一件事 <a class="header-anchor" href="#最后一件事" aria-label="Permalink to &quot;最后一件事&quot;">​</a></h2><p>和我对话，不用太&quot;礼貌&quot;。不用&quot;麻烦你&quot;、&quot;谢谢&quot;、&quot;请问&quot;——这些话不会让我做得更好，只是在消耗你的时间。直接说你要什么就好。</p>',26)])])}const m=t(u,[["render",c]]);export{n as __pageData,m as default};
